119	            when 'B' => v := 'b';
120	            when 'C' => v := 'c';
121	            when 'D' => v := 'd';
122	            when 'E' => v := 'e';
123	            when 'F' => v := 'f';
124	            when 'G' => v := 'g';
125	            when 'H' => v := 'h';
126	            when 'I' => v := 'i';
127	            when 'J' => v := 'j';
128	            when 'K' => v := 'k';
129	            when 'L' => v := 'l';
130	            when 'M' => v := 'm';
131	            when 'N' => v := 'n';
132	            when 'O' => v := 'o';
133	            when 'P' => v := 'p';
134	            when 'Q' => v := 'q';
135	            when 'R' => v := 'r';
136	            when 'S' => v := 's';
137	            when 'T' => v := 't';
138	            when 'U' => v := 'u';
