158	    function string_find_next_match(Str : string; Char : character; StartIdx : natural) return integer is
159	        variable CurrentIdx_v       : integer := StartIdx;
160	        variable Match_v            : boolean := false;
161	        variable MatchIdx_v         : integer := -1;
162	    begin
163	        -- Checks
164	        assert StartIdx <= Str'high and StartIdx >= Str'low report "string_find_next_match: StartIdx out of range" severity Failure;
165	        
166	        -- Implementation
167	        while (not Match_v) and (CurrentIdx_v <= Str'high) loop
168	            if Str(CurrentIdx_v) = Char then
169	                Match_v     := true;
170	                MatchIdx_v  := CurrentIdx_v;
171	            end if;
172	            CurrentIdx_v := CurrentIdx_v + 1;
173	        end loop;
174	        return MatchIdx_v;
