200	    function string_parse_int(Str : string; StartIdx : natural) return integer is
201	        variable CurrentIdx_v       : integer   := StartIdx;
202	        variable IsNegative_v       : boolean   := false;
203	        variable AbsoluteVal_v      : integer   := 0;
204	    begin
205	        -- Checks
206	        assert StartIdx <= Str'high and StartIdx >= Str'low report "string_parse_int: StartIdx out of range" severity Failure;
207	        
208	        -- Remove leading spaces
209	        while Str(CurrentIdx_v) = ' ' loop
210	            CurrentIdx_v := CurrentIdx_v + 1;
211	        end loop;
212	        
213	        -- Detect negative numbers
214	        if Str(CurrentIdx_v) = '-' then
215	            IsNegative_v := true;
216	            CurrentIdx_v := CurrentIdx_v + 1;
217	        end if;
218	        
219	        -- Parse absolute value
220	        while (CurrentIdx_v <= Str'high) loop
221	            if not string_char_is_numeric(Str(CurrentIdx_v)) then
222	                CurrentIdx_v := Str'high+1;
223	            else
224	                AbsoluteVal_v := AbsoluteVal_v * 10 + string_int_from_char(Str(CurrentIdx_v));
225	                CurrentIdx_v := CurrentIdx_v + 1;
226	            end if;
227	        end loop;
228	        
229	        -- Return number with correct sign
230	        if IsNegative_v then
231	            return -AbsoluteVal_v;
232	        else
233	            return AbsoluteVal_v;
234	        end if;
