94	    function cl_fix_abs_fmt(a_fmt : FixFormat_t) return FixFormat_t;
95	    
96	    function cl_fix_shift_fmt(a_fmt : FixFormat_t; min_shift : integer; max_shift : integer) return FixFormat_t;
97	    function cl_fix_shift_fmt(a_fmt : FixFormat_t; shift : integer) return FixFormat_t;
98	    
99	    function cl_fix_round_fmt(a_fmt : FixFormat_t; r_frac_bits : integer; rnd : FixRound_t) return FixFormat_t;
100	    
101	    function choose(condition : boolean; a_fmt, b_fmt : FixFormat_t) return FixFormat_t;
102	    
103	    -----------------------------------------------------------------------------------------------
104	    -- String Conversions
105	    -----------------------------------------------------------------------------------------------
106	    function to_string(a : std_logic_vector; a_fmt : FixFormat_t) return string;
107	    
108	    function to_string(fmt : FixFormat_t) return string;
109	    
110	    function to_string(rnd : FixRound_t) return string;
111	    
112	    function to_string(sat : FixSaturate_t) return string;
113	    
114	    function cl_fix_format_from_string(Str : string) return FixFormat_t;
