119	
120	    -----------------------------------------------------------------------------------------------
121	    -- Type Conversions
122	    -----------------------------------------------------------------------------------------------
123	    function cl_fix_from_real(a : real; result_fmt : FixFormat_t; saturate : FixSaturate_t := SatWarn_s) return std_logic_vector;
124	    
125	    function cl_fix_to_real(a : std_logic_vector; a_fmt : FixFormat_t) return real;
126	    
127	    function cl_fix_to_integer(a : std_logic_vector; aFmt : FixFormat_t) return integer;
128	    
129	    function cl_fix_from_integer(a : integer; aFmt : FixFormat_t) return std_logic_vector;
130	
131	    -----------------------------------------------------------------------------------------------
132	    -- Rounding and Saturation
133	    -----------------------------------------------------------------------------------------------
134	    function cl_fix_round(
135	        a           : std_logic_vector;
136	        a_fmt       : FixFormat_t;
137	        result_fmt  : FixFormat_t;
138	        round       : FixRound_t := Trunc_s;
139	        fmt_check   : boolean := true
140	    ) return std_logic_vector;
141	    
142	    function cl_fix_saturate(
