800	    function cl_fix_from_real(a : real; result_fmt : FixFormat_t; saturate : FixSaturate_t := SatWarn_s) return std_logic_vector is
801	        -- Several toolchains have bugs in ieee.math_real."mod" (Vivado, Efinity, Gowin EDA).
802	        -- Therefore, this local function is used as a workaround.
803	        function real_mod(a, b : real) return real is
804	        begin
805	            return a - b * floor(a/b);
806	        end function;
807	        
808	        constant ChunkSize_c    : positive := 30;
809	        constant ChunkCount_c   : positive := (cl_fix_width(result_fmt) + ChunkSize_c - 1)/ChunkSize_c;
810	        variable ASat_v         : real;
811	        variable Chunk_v        : std_logic_vector(ChunkSize_c-1 downto 0);
812	        variable Result_v       : std_logic_vector(ChunkSize_c*ChunkCount_c-1 downto 0);
813	    begin
814	        -- Saturation is mandatory in this function (because wrapping has not been implemented)
815	        assert saturate = SatWarn_s or saturate = Sat_s
816	            report "cl_fix_for_real: Saturation mode must be SatWarn_s or Sat_s"
817	            severity Failure;
818	            
819	        -- Saturate
820	        if a > max_real(result_fmt) then
821	            ASat_v := max_real(result_fmt);
822	        elsif a < min_real(result_fmt) then
823	            ASat_v := min_real(result_fmt);
824	        else
825	            ASat_v := a;
826	        end if;
827	        
828	        -- Rescale to appropriate fractional bits, with half-up rounding
829	        ASat_v := floor(ASat_v * 2.0**result_fmt.F + 0.5);
830	        
831	        -- Convert to fixed-point in chunks (required for formats that don't fit into integer)
832	        for i in 0 to ChunkCount_c-1 loop
833	            Chunk_v := std_logic_vector(to_unsigned(integer(real_mod(ASat_v, 2.0**ChunkSize_c)), ChunkSize_c));
834	            Result_v((i+1)*ChunkSize_c-1 downto i*ChunkSize_c) := Chunk_v;
835	            ASat_v := floor(ASat_v/2.0**ChunkSize_c);
836	        end loop;
837	        
838	        return Result_v(cl_fix_width(result_fmt)-1 downto 0);
839	    end;
840	    
841	    function cl_fix_to_real(a : std_logic_vector; a_fmt : FixFormat_t) return real is
842	        constant ABits_c        : natural := cl_fix_width(a_fmt);
843	        constant ChunkSize_c    : positive := 30;
844	        constant ChunkCount_c   : natural := (ABits_c + ChunkSize_c - 1)/ChunkSize_c;
845	        variable a_v            : std_logic_vector(a'length-1 downto 0);
846	        variable Correction_v   : real := 0.0;
847	        variable apad_v         : unsigned(ChunkSize_c*ChunkCount_c-1 downto 0);
848	        variable Chunk_v        : unsigned(ChunkSize_c-1 downto 0);
849	        variable result_v       : real := 0.0;
850	    begin
851	        -- Enforce 'downto' bit order
852	        a_v := a;
853	        
854	        -- Handle sign bit
855	        if a_fmt.S = 1 and a_v(ABits_c-1) = '1' then
856	            a_v(ABits_c-1) := '0'; -- Clear sign bit.
857	            Correction_v := -2.0**(ABits_c-1 - a_fmt.F); -- Remember its weight.
858	        end if;
859	        
860	        -- Resize to an integer number of chunks
861	        apad_v := resize(unsigned(a_v), ChunkSize_c*ChunkCount_c);
862	        
863	        -- Convert to real in chunks
864	        for i in ChunkCount_c-1 downto 0 loop
865	            result_v := result_v * 2.0**ChunkSize_c; -- Shift to next chunk.
866	            Chunk_v := apad_v((i+1)*ChunkSize_c-1 downto i*ChunkSize_c);
867	            result_v := result_v + real(to_integer(Chunk_v)) * 2.0**(-a_fmt.F);
868	        end loop;
869	        
870	        -- Add sign bit contribution
871	        result_v := result_v + Correction_v;
872	        
873	        return result_v;
874	    end;
