876	    function cl_fix_from_integer(a : integer; aFmt : FixFormat_t) return std_logic_vector is
877	    begin
878	        if aFmt.S = 1 then
879	            return std_logic_vector(to_signed(a, cl_fix_width(aFmt)));
880	        else
881	            return std_logic_vector(to_unsigned(a, cl_fix_width(aFmt)));
882	        end if;
883	    end function;
