885	    function cl_fix_to_integer(a : std_logic_vector; aFmt : FixFormat_t) return integer is
886	        -- Force downto 0
887	        constant a_c    : std_logic_vector(a'length-1 downto 0) := a;
888	    begin
889	        -- Modelsim throws warnings if to_integer() is called on 1-bit signed or any 0-bit input.
890	        -- We handle these special cases explicitly to avoid the warnings.
891	        if cl_fix_width(aFmt) = 0 then
892	            return 0;
893	        elsif aFmt.S = 1 and cl_fix_width(aFmt) = 1 then
894	            if a_c(0) = '1' then
895	                -- Note: -1 in the integer representation is -2**aFmt.I in fixed point.
896	                return -1;
897	            else
898	                return 0;
899	            end if;
900	        end if;
901	        
902	        -- Normal cases
903	        if aFmt.S = 1 then
904	            return to_integer(signed(a_c));
905	        else
906	            return to_integer(unsigned(a_c));
907	        end if;
908	    end function;
