1009	    function cl_fix_resize(
1010	        a           : std_logic_vector;
1011	        a_fmt       : FixFormat_t;
1012	        result_fmt  : FixFormat_t;
1013	        round       : FixRound_t    := Trunc_s;
1014	        saturate    : FixSaturate_t := Warn_s
1015	    ) return std_logic_vector is
1016	        -- Round
1017	        constant rounded_fmt_c  : FixFormat_t := cl_fix_round_fmt(a_fmt, result_fmt.F, round);
1018	        constant rounded_c      : std_logic_vector := cl_fix_round(a, a_fmt, rounded_fmt_c, round);
1019	    begin
1020	        -- Saturate
1021	        return cl_fix_saturate(rounded_c, rounded_fmt_c, result_fmt, saturate);
1022	    end;
