1041	    function cl_fix_recommended_pipelining(
1042	        a_fmt       : FixFormat_t;
1043	        result_fmt  : FixFormat_t;
1044	        round       : FixRound_t;
1045	        fmt_check   : boolean := true
1046	    ) return natural is
1047	    begin
1048	        -- Allow the designer to ignore the worst-case result format (with caution).
1049	        if fmt_check then
1050	            assert result_fmt = cl_fix_round_fmt(a_fmt, result_fmt.F, round)
1051	                report "cl_fix_recommended_pipelining: Invalid result format. Use cl_fix_round_fmt()." severity Failure;
1052	        end if;
1053	        
1054	        -- Registering is not needed if zero logic is used. This happens in two cases:
1055	        -- (1) During truncation.
1056	        if round = Trunc_s then
1057	            return 0;
1058	        else
1059	            -- If a new rounding mode is defined, then appropriate behavior must be implemented.
1060	            assert round = NonSymPos_s or round = NonSymNeg_s or round = SymInf_s or round = SymZero_s or round = ConvEven_s or round = ConvOdd_s
1061	                report "cl_fix_recommended_pipelining: Unhandled rounding mode."
1062	                severity Failure;
1063	        end if;
1064	        -- (2) If the number of fractional bits isn't being decreased.
1065	        if result_fmt.F >= a_fmt.F then
1066	            return 0;
1067	        end if;
1068	        return 1;
1069	    end;
1070	    
1071	    function cl_fix_recommended_pipelining(
1072	        a_fmt       : FixFormat_t;
1073	        result_fmt  : FixFormat_t;
1074	        saturate    : FixSaturate_t
1075	    ) return natural is
1076	    begin
1077	        assert result_fmt.F = a_fmt.F
1078	            report "cl_fix_recommended_pipelining: Number of frac bits cannot change during saturation."
1079	            severity Failure;
1080	        
1081	        -- Registering is not needed if zero logic is used. This happens in two cases:
1082	        -- (1) During wrapping.
1083	        if saturate = None_s or saturate = Warn_s then
1084	            return 0;
1085	        else
1086	            -- If a new saturation mode is defined, then appropriate behavior must be implemented.
1087	            assert saturate = Sat_s or saturate = SatWarn_s
1088	                report "cl_fix_recommended_pipelining: Unhandled saturation mode."
1089	                severity Failure;
1090	        end if;
1091	        -- (2) If the number of integer bits is not being decreased, and the number of sign bits is
1092	        --     not being changed.
1093	        if result_fmt.I >= a_fmt.I and result_fmt.S = a_fmt.S then
1094	            return 0;
1095	        end if;
1096	        return 1;
1097	    end;
1098	    
1099	    function cl_fix_recommended_pipelining(
1100	        a_fmt       : FixFormat_t;
1101	        result_fmt  : FixFormat_t;
1102	        round       : FixRound_t;
1103	        saturate    : FixSaturate_t
1104	    ) return natural is
1105	        constant round_fmt_c    : FixFormat_t := cl_fix_round_fmt(a_fmt, result_fmt.F, round);
1106	    begin
1107	        return cl_fix_recommended_pipelining(a_fmt, round_fmt_c, round)
1108	             + cl_fix_recommended_pipelining(round_fmt_c, result_fmt, saturate);
1109	    end;
